{
var input = inputs.Length > 0 && inputs[0] != null ? inputs[0]! :
        new PixelBuffer(context.TileSize, context.TileSize);

    var channel = GetChoice(parameters, "channel", "luminance");
    var offset = GetFloat(parameters, "offset", 0f);
    var contrast = GetFloat(parameters, "contrast", 1f);
    var blendMode = GetChoice(parameters, "blendMode", "replace");
    var opacity = GetFloat(parameters, "opacity", 1f);
    var invert = GetBool(parameters, "invert", false);

    var c0 = GetColor(parameters, "shadowColor", System.Windows.Media.Color.FromRgb(20, 10, 50));
    var c1 = GetColor(parameters, "midColor1", System.Windows.Media.Color.FromRgb(60, 80, 140));
    var c2 = GetColor(parameters, "midColor2", System.Windows.Media.Color.FromRgb(160, 140, 80));
    var c3 = GetColor(parameters, "highlightColor", System.Windows.Media.Color.FromRgb(240, 220, 180));

    var stops = new[]
    {
        (0f, c0.R / 255f, c0.G / 255f, c0.B / 255f),
        (0.35f, c1.R / 255f, c1.G / 255f, c1.B / 255f),
        (0.65f, c2.R / 255f, c2.G / 255f, c2.B / 255f),
        (1f, c3.R / 255f, c3.G / 255f, c3.B / 255f)
    };

    var size = context.TileSize;
    var output = new PixelBuffer(size, size);

    output.ParallelForEachPixel((x, y) =>
    {
        var (r, g, b, a) = input.GetPixel(x, y);

        var val = channel switch
        {
            "red" => r,
            "green" => g,
            "blue" => b,
            "alpha" => a,
            _ => r * 0.299f + g * 0.587f + b * 0.114f
        };

        if (invert) val = 1f - val;

        // Apply offset and contrast
        val = (val - 0.5f + offset) * contrast + 0.5f;
        val = Math.Clamp(val, 0f, 1f);

        // Sample gradient
        float mapR, mapG, mapB;
        if (val <= stops[0].Item1)
        {
            mapR = stops[0].Item2; mapG = stops[0].Item3; mapB = stops[0].Item4;
        }
        else if (val >= stops[3].Item1)
        {
            mapR = stops[3].Item2; mapG = stops[3].Item3; mapB = stops[3].Item4;
        }
        else
        {
            var idx = 0;
            for (var i = 0; i < 3; i++)
            {
                if (val >= stops[i].Item1 && val <= stops[i + 1].Item1)
                { idx = i; break; }
            }

            var t = (val - stops[idx].Item1) / (stops[idx + 1].Item1 - stops[idx].Item1);
            t = Math.Clamp(t, 0f, 1f);

            mapR = Lerp(stops[idx].Item2, stops[idx + 1].Item2, t);
            mapG = Lerp(stops[idx].Item3, stops[idx + 1].Item3, t);
            mapB = Lerp(stops[idx].Item4, stops[idx + 1].Item4, t);
        }

        // Blend with original
        var op = opacity;
        (mapR, mapG, mapB) = blendMode switch
        {
            "overlay" => (
                Lerp(r, OverlayBlend(r, mapR), op),
                Lerp(g, OverlayBlend(g, mapG), op),
                Lerp(b, OverlayBlend(b, mapB), op)
            ),
            "softLight" => (
                Lerp(r, SoftLightBlend(r, mapR), op),
                Lerp(g, SoftLightBlend(g, mapG), op),
                Lerp(b, SoftLightBlend(b, mapB), op)
            ),
            _ => (mapR, mapG, mapB) // replace
        };

        output.SetPixel(x, y, Math.Clamp(mapR, 0f, 1f), Math.Clamp(mapG, 0f, 1f), Math.Clamp(mapB, 0f, 1f), a);
    });

    return output;

private static float OverlayBlend(float base_, float blend)
{
    return base_ < 0.5f
        ? 2f * base_ * blend
        : 1f - 2f * (1f - base_) * (1f - blend);
}

private static float SoftLightBlend(float base_, float blend)
{
    return blend < 0.5f
        ? 2f * base_ * blend + base_ * base_ * (1f - 2f * blend)
        : 2f * base_ * (1f - blend) + MathF.Sqrt(base_) * (2f * blend - 1f);
    }
}
